/* JYS HR — App shell, login, navigation */
const { useState, useEffect, useMemo, useRef, useCallback } = React;
const D = window.JYS_DATA;
// Components from sibling scripts (loaded before this file)
const Dashboard    = window.Dashboard;
const HRScreen     = window.HRScreen;
const ViolationLog = window.ViolationLog;
const CatalogScreen= window.CatalogScreen;
const MyProfile    = window.MyProfile;
const MyViolations = window.MyViolations;
const QuizScreen   = window.QuizScreen;

/* ---------- Toast ---------- */
function useToast(){
  const [msg, setMsg] = useState(null);
  const tRef = useRef();
  const show = useCallback((text, kind="ok")=>{
    setMsg({text, kind});
    clearTimeout(tRef.current);
    tRef.current = setTimeout(()=>setMsg(null), 2600);
  },[]);
  const node = msg ? <div className={"toast show "+(msg.kind==="err"?"err":"")}>{msg.text}</div> : null;
  return [show, node];
}

/* ---------- Avatar ---------- */
function Avatar({ name, dark=false, lg=false }) {
  return <span className={`av${lg?" lg":""}${dark?" dark":""}`}>{D.initials(name)}</span>;
}

/* ---------- Login ---------- */
function LoginScreen({ employees, onLogin }) {
  const [mode, setMode] = useState("staff"); // staff | mgr
  const [empId, setEmpId] = useState("");
  const [pinDigits, setPinDigits] = useState(["","","",""]);
  const [mgrPwd, setMgrPwd] = useState("");
  const [err, setErr] = useState("");
  const pinRefs = useRef([]);

  const pin = pinDigits.join("");

  function setPinAt(i, val) {
    val = val.replace(/\D/g,"").slice(-1);
    const next = pinDigits.slice();
    next[i] = val;
    setPinDigits(next);
    if (val && i<3) pinRefs.current[i+1]?.focus();
  }
  function onPinKey(i, e) {
    if (e.key==="Backspace" && !pinDigits[i] && i>0) {
      const next = pinDigits.slice();
      next[i-1] = "";
      setPinDigits(next);
      pinRefs.current[i-1]?.focus();
    }
    if (e.key==="Enter") submit();
  }

  // Demo-only mã quản lý — prototype chỉ dùng để xem giao diện. KHÔNG dùng giá trị này trong bản production.
  const DEMO_MGR_CODE = "demo-manager";

  function submit() {
    setErr("");
    if (mode==="mgr") {
      if (mgrPwd.trim() === DEMO_MGR_CODE) {
        onLogin({ role:"manager" });
      } else {
        setErr(`Sai mã quản lý. Mã demo: ${DEMO_MGR_CODE}`);
      }
    } else {
      const emp = employees.find(e=>e.id===empId);
      if (!emp) { setErr("Chọn tên của bạn"); return; }
      if (!/^\d{4}$/.test(pin)) { setErr("Mã cá nhân gồm 4 chữ số"); return; }
      if (String(emp.maCaNhan) !== pin) { setErr(`Sai mã cá nhân. Mã demo của ${emp.hoTen.split(" ").slice(-1)[0]}: ${emp.maCaNhan}`); return; }
      onLogin({ role:"staff", empId });
    }
  }

  function demoMgr() {
    setMode("mgr"); setMgrPwd(DEMO_MGR_CODE); setErr("");
    setTimeout(()=>onLogin({ role:"manager" }), 120);
  }
  function demoStaff(id, code) {
    setMode("staff"); setEmpId(id); setPinDigits(code.split("")); setErr("");
    setTimeout(()=>onLogin({ role:"staff", empId:id }), 120);
  }

  const sortedEmp = [...employees].sort((a,b)=>String(a.hoTen).localeCompare(String(b.hoTen),"vi"));

  return (
    <div className="login-shell">
      <div className="login-card">
        <img className="logo" src="data:image/jpeg;base64," alt="JYS IELTS" />
        <h1>Hệ thống quản lý nhân sự</h1>
        <div className="tag">Trung tâm Anh ngữ Quốc tế JYS</div>

        <div className="seg">
          <button className={mode==="staff"?"on":""} onClick={()=>{setMode("staff"); setErr("");}}>Nhân viên</button>
          <button className={mode==="mgr"?"on":""} onClick={()=>{setMode("mgr"); setErr("");}}>Quản lý</button>
        </div>

        {mode==="staff" ? (
          <>
            <div className="login-field">
              <label>Chọn tên của bạn</label>
              <select value={empId} onChange={e=>{setEmpId(e.target.value); setErr("");}}>
                <option value="">— Chọn tên —</option>
                {sortedEmp.map(e=>(
                  <option key={e.id} value={e.id}>{e.hoTen} — {e.chiNhanh}</option>
                ))}
              </select>
            </div>
            <div className="login-field">
              <label>Mã cá nhân <span className="hint">(4 số do quản lý cấp)</span></label>
              <div className="pin-input">
                {[0,1,2,3].map(i=>(
                  <input key={i} ref={el=>pinRefs.current[i]=el} type="text" inputMode="numeric" maxLength="1"
                    value={pinDigits[i]} onChange={e=>setPinAt(i, e.target.value)}
                    onKeyDown={e=>onPinKey(i,e)} aria-label={`Chữ số ${i+1}`} />
                ))}
              </div>
            </div>
          </>
        ) : (
          <div className="login-field">
            <label>Mã quản lý</label>
            <input type="password" value={mgrPwd} onChange={e=>setMgrPwd(e.target.value)}
              onKeyDown={e=>e.key==="Enter"&&submit()} placeholder="Nhập mã quản lý" autoFocus />
          </div>
        )}

        <div className={"login-msg "+(err?"err":"")}>{err||"\u00A0"}</div>
        <button className="btn full" onClick={submit}>Đăng nhập</button>

        <div className="demo-row">
          <button onClick={demoMgr}>Demo: vào với tư cách Quản lý</button>
          <button onClick={()=>demoStaff("e03","5026")}>Demo: nhân viên (Trần Bảo Châu)</button>
          <button onClick={()=>demoStaff("e08","1207")}>Demo: nhân viên (Bùi Thanh Tùng)</button>
        </div>

        <div className="login-foot">
          Nhân viên xem được hồ sơ và lỗi vi phạm của riêng mình.<br/>
          Quản lý nhập và sửa toàn bộ dữ liệu.
        </div>
      </div>
    </div>
  );
}

/* ---------- App Shell ---------- */
const TABS_MANAGER = [
  { id:"dash",   label:"Tổng quan" },
  { id:"hr",     label:"Hồ sơ nhân sự" },
  { id:"log",    label:"Ghi nhận vi phạm" },
  { id:"cat",    label:"Danh mục lỗi" },
  { id:"quiz",   label:"Kiểm tra" },
];
const TABS_STAFF = [
  { id:"me",     label:"Hồ sơ của tôi" },
  { id:"myviol", label:"Lỗi của tôi" },
  { id:"cat",    label:"Danh mục lỗi" },
  { id:"quiz",   label:"Kiểm tra" },
];

function AppShell({ session, employees, violations, quizzes, onLogout,
                    onSaveEmployee, onDeleteEmployee, onSaveViolation, onDeleteViolation,
                    onSaveQuiz, showToast }) {
  const isMgr = session.role === "manager";
  const tabs = isMgr ? TABS_MANAGER : TABS_STAFF;
  const [tab, setTab] = useState(isMgr ? "dash" : "me");
  const [openEmp, setOpenEmp] = useState(null); // employee detail modal id

  const me = !isMgr ? employees.find(e=>e.id===session.empId) : null;
  const myViolations = me ? violations.filter(v=>v.empId===me.id) : [];

  return (
    <div className="app-shell">
      <div className="skybar"></div>
      <header className="top">
        <div className="top-inner">
          <div className="brand">
            <img className="logo" src="data:image/jpeg;base64," alt="JYS" />
            <div className="titles">
              <h1>Quản lý nhân sự JYS</h1>
              <div className="sub">Trung tâm Anh ngữ Quốc tế · Đô Lương · Vinh · Văn Hiến</div>
            </div>
            <div className="who">
              {isMgr ? (
                <div className="whoami">
                  <span className="nm">Phòng HCNS</span>
                  <span className="rl">Toàn quyền</span>
                </div>
              ) : (
                <div className="whoami">
                  <span className="nm">{me?.hoTen}</span>
                  <span className="rl">{me?.viTri} · {me?.chiNhanh}</span>
                </div>
              )}
              <span className={"chip"+(isMgr?" mgr":"")}>{isMgr?"Quản lý":"Nhân viên"}</span>
              <button className="btn ghost sm" onClick={onLogout}>Đăng xuất</button>
            </div>
          </div>
          <nav className="tabs">
            {tabs.map(t=>(
              <button key={t.id} className={"tab"+(tab===t.id?" active":"")} onClick={()=>setTab(t.id)}>
                {t.label}
              </button>
            ))}
          </nav>
        </div>
      </header>

      <div className="wrap">
        <div className="panel" key={tab}>
          {isMgr && tab==="dash"   && <Dashboard employees={employees} violations={violations} onOpenEmp={setOpenEmp} />}
          {isMgr && tab==="hr"     && <HRScreen employees={employees} onSave={onSaveEmployee} onDelete={onDeleteEmployee} onOpenEmp={setOpenEmp} showToast={showToast} />}
          {isMgr && tab==="log"    && <ViolationLog employees={employees} violations={violations} onSave={onSaveViolation} onDelete={onDeleteViolation} showToast={showToast} />}
          {tab==="cat"             && <CatalogScreen />}
          {tab==="quiz"            && <QuizScreen me={me} isMgr={isMgr} quizzes={quizzes} onSaveQuiz={onSaveQuiz} showToast={showToast} />}
          {!isMgr && tab==="me"    && <MyProfile me={me} />}
          {!isMgr && tab==="myviol"&& <MyViolations me={me} violations={myViolations} />}
        </div>
      </div>

      {openEmp && (
        <EmployeeModal
          emp={employees.find(e=>e.id===openEmp)}
          violations={violations.filter(v=>v.empId===openEmp)}
          onClose={()=>setOpenEmp(null)}
        />
      )}
    </div>
  );
}

/* ---------- Employee detail modal (used by manager) ---------- */
function EmployeeModal({ emp, violations, onClose }) {
  if (!emp) return null;
  useEffect(()=>{
    function onKey(e){ if(e.key==="Escape") onClose(); }
    document.addEventListener("keydown", onKey);
    document.body.style.overflow="hidden";
    return ()=>{ document.removeEventListener("keydown", onKey); document.body.style.overflow=""; };
  },[]);

  const hang = D.tinhHang(emp.luongThang);
  const tn = D.thamNien(emp.ngayVaoLam);
  const cs = D.trangThaiHopDong(emp);
  const tongPhat = violations.reduce((s,v)=>s+Number(v.amount||0), 0);
  const luongNam = Number(emp.luongThang||0) * 12;

  return (
    <div className="modal-bg" onClick={onClose}>
      <div className="modal" onClick={e=>e.stopPropagation()}>
        <div className="modal-h">
          <Avatar name={emp.hoTen} lg dark />
          <div>
            <div className="nm">{emp.hoTen}</div>
            <div className="rl">{emp.viTri} · {emp.chiNhanh} · Mã NV {emp.maNV}</div>
          </div>
          <button className="close" onClick={onClose} aria-label="Đóng">×</button>
        </div>
        <div className="modal-body">
          <RankBanner hang={hang} luong={emp.luongThang} />
          <ProfileSections emp={emp} hang={hang} tn={tn} cs={cs} luongNam={luongNam} tongPhat={tongPhat} viCount={violations.length} />
        </div>
      </div>
    </div>
  );
}

function RankBanner({ hang, luong }) {
  return (
    <div className="rank-banner">
      <div>
        <div className="rt">Hạng nghề nghiệp</div>
        <div className="rn">{hang.ten}</div>
        <div className="rd">{hang.desc}</div>
        <div className="rank-steps">
          {[0,1,2,3].map(i=>(
            <i key={i} className={i<=hang.idx?"on":""}></i>
          ))}
        </div>
      </div>
      <div className="right">
        <div className="rt">Lương tháng hiện tại</div>
        <div className="rn">{D.fmtMoney(luong)}</div>
        <div className="rd">{D.fmtMoney(Number(luong||0)*12)}/năm</div>
      </div>
    </div>
  );
}

function ProfileSections({ emp, hang, tn, cs, luongNam, tongPhat, viCount }) {
  return (
    <>
      <h3 className="section-title">Thông tin cơ bản</h3>
      <div className="card">
        <div className="card-pad">
          <div className="prof-grid">
            <KV k="Họ và tên" v={emp.hoTen}/>
            <KV k="Mã nhân viên" v={emp.maNV}/>
            <KV k="Ngày sinh" v={D.fmtDate(emp.ngaySinh)}/>
            <KV k="Số điện thoại" v={emp.soDienThoai}/>
            <KV k="Email" v={emp.email}/>
            <KV k="Chi nhánh" v={emp.chiNhanh}/>
          </div>
        </div>
      </div>

      <h3 className="section-title">Công việc và hợp đồng</h3>
      <div className="card">
        <div className="card-pad">
          <div className="prof-grid">
            <KV k="Vị trí" v={emp.viTri}/>
            <KV k="Ngày vào làm" v={D.fmtDate(emp.ngayVaoLam)}/>
            <KV k="Thâm niên" v={D.chuoiThamNien(emp.ngayVaoLam)}/>
            <KV k="Loại hợp đồng" v={emp.loaiHopDong}/>
            <KV k="Hợp đồng từ" v={D.fmtDate(emp.hopDongTu)}/>
            <KV k="Hợp đồng đến" v={<span><span style={{marginRight:8}}>{emp.hopDongDen?D.fmtDate(emp.hopDongDen):"Không xác định"}</span><span className={"cs "+cs.kind}>{cs.label}</span></span>}/>
          </div>
        </div>
      </div>

      <h3 className="section-title">Lương và quyền lợi</h3>
      <div className="card">
        <div className="card-pad">
          <div className="prof-grid">
            <KV k="Lương tháng" v={D.fmtMoney(emp.luongThang)}/>
            <KV k="Lương năm (tự tính)" v={D.fmtMoney(luongNam)}/>
            <KV k="Hạng nghề nghiệp" v={<span className={`pill rank r${hang.idx+1}`}>{hang.ten}</span>}/>
            <KV k="Tổng phạt từ trước đến nay" v={<span style={{color:tongPhat>0?"var(--warn)":"var(--ink)"}}>{D.fmtMoney(tongPhat)} <span style={{color:"var(--ink-faint)",fontWeight:500,fontSize:12}}>· {viCount} lần</span></span>}/>
          </div>
          <hr className="sep"/>
          <div className="field" style={{marginBottom:8}}>
            <label>Quyền lợi khác</label>
            <div className="subtle" style={{whiteSpace:"pre-wrap"}}>{emp.quyenLoiKhac || "—"}</div>
          </div>
          <div className="field" style={{marginBottom:0}}>
            <label>Ghi chú nội bộ</label>
            <div className="subtle" style={{whiteSpace:"pre-wrap"}}>{emp.ghiChu || "—"}</div>
          </div>
        </div>
      </div>
    </>
  );
}

function KV({ k, v }) {
  return (
    <div className="prof-row">
      <span className="pk">{k}</span>
      <span className="pv">{v ?? "—"}</span>
    </div>
  );
}

/* ---------- Root App ---------- */
function App() {
  const [session, setSession] = useState(null);
  const [employees, setEmployees] = useState(D.EMPLOYEES_SEED);
  const [violations, setViolations] = useState(D.VIOLATIONS_SEED);
  const [quizzes, setQuizzes] = useState(D.QUIZ_SEED);
  const [showToast, toastNode] = useToast();

  function onSaveEmployee(rec) {
    setEmployees(prev=>{
      const i = prev.findIndex(e=>e.id===rec.id);
      if (i>=0) { const next=[...prev]; next[i]=rec; return next; }
      return [...prev, rec];
    });
    showToast("Đã lưu hồ sơ");
  }
  function onDeleteEmployee(id) {
    if(!confirm("Xóa nhân viên này? Toàn bộ vi phạm và bài kiểm tra liên quan sẽ bị xóa.")) return;
    setEmployees(prev=>prev.filter(e=>e.id!==id));
    setViolations(prev=>prev.filter(v=>v.empId!==id));
    setQuizzes(prev=>prev.filter(k=>k.empId!==id));
    showToast("Đã xóa nhân viên");
  }
  function onSaveViolation(rec) {
    setViolations(prev=>{
      const i = prev.findIndex(v=>v.id===rec.id);
      if (i>=0) { const next=[...prev]; next[i]=rec; return next; }
      return [...prev, rec];
    });
    showToast("Đã ghi nhận vi phạm");
  }
  function onDeleteViolation(id) {
    if(!confirm("Xóa bản ghi vi phạm này?")) return;
    setViolations(prev=>prev.filter(v=>v.id!==id));
    showToast("Đã xóa vi phạm");
  }
  function onSaveQuiz(rec) {
    setQuizzes(prev=>[...prev, rec]);
  }

  if (!session) {
    return (
      <>
        <LoginScreen employees={employees} onLogin={setSession} />
        {toastNode}
      </>
    );
  }
  return (
    <>
      <AppShell
        session={session}
        employees={employees}
        violations={violations}
        quizzes={quizzes}
        onLogout={()=>setSession(null)}
        onSaveEmployee={onSaveEmployee}
        onDeleteEmployee={onDeleteEmployee}
        onSaveViolation={onSaveViolation}
        onDeleteViolation={onDeleteViolation}
        onSaveQuiz={onSaveQuiz}
        showToast={showToast}
      />
      {toastNode}
    </>
  );
}

window.JYS_APP = { App, Avatar, KV, RankBanner, ProfileSections };
window.App = App;
